    // Try to load icons dynamically from the pattern configuration file.
    $yaml_file = DRUPAL_ROOT . '/themes/custom/commu/templates/patterns/atoms/icon/a-icon.ui_patterns.yml';

    if (file_exists($yaml_file)) {
      try {
        // Parse the YAML file to get icon options.
        $yaml_content = file_get_contents($yaml_file);
        $pattern_config = \Drupal\Component\Serialization\Yaml::decode($yaml_content);

        // Extract icon options from the pattern configuration.
        if (isset($pattern_config['a_icon']['settings']['icon']['options'])) {
          return $pattern_config['a_icon']['settings']['icon']['options'];
        }
      }
      catch (\Exception $e) {
        // If parsing fails, fall back to a default set.
        \Drupal::logger('commu_landing')->error('Failed to parse icon pattern file: @error', ['@error' => $e->getMessage()]);
      }
    }

    // Fallback to a minimal set of commonly used icons if file cannot be read.
    return [
      'document' => 'Document',
