  /**
   * Génère un nom d'utilisateur unique.
   */
  protected function generateUsername(string $first_name, string $last_name): string {
    $base_username = strtolower($first_name . '.' . $last_name);
    $base_username = preg_replace('/[^a-z0-9.]/', '', $base_username);

    $username = $base_username;
    $counter = 1;

    while ($this->usernameExists($username)) {
      $username = $base_username . $counter;
      $counter++;
    }

    return $username;
  }

  /**
   * Vérifie si un nom d'utilisateur existe.
   */
  protected function usernameExists(string $username): bool {
    $users = $this->entityTypeManager->getStorage('user')
      ->loadByProperties(['name' => $username]);

    return !empty($users);
  }

