   * Sets the path alias for a node.
   *
   * @param \Drupal\node\NodeInterface $node
   *   The node.
   * @param string $path
   *   The desired path alias.
   */
  protected function setPathAlias(NodeInterface $node, string $path): void {
    $path_alias_storage = $this->entityTypeManager->getStorage('path_alias');

    // Ensure path starts with /.
    if (strpos($path, '/') !== 0) {
      $path = '/' . $path;
    }

    // Delete existing aliases for this node.
    $existing = $path_alias_storage->loadByProperties([
      'path' => '/node/' . $node->id(),
    ]);
    foreach ($existing as $alias) {
      $alias->delete();
    }

    // Create new alias.
    $path_alias_storage->create([
      'path' => '/node/' . $node->id(),
      'alias' => $path,
      'langcode' => 'fr',
    ])->save();
  }

